1	import Link from "next/link";
2	import { notFound, redirect } from "next/navigation";
3	
4	import PublishToToolbar from "@/components/PublishToToolbar";
5	import PublishToggle from "@/components/PublishToggle";
6	import { getFounder } from "@/lib/auth";
7	import { db } from "@/lib/db";
8	import {
9	  activeEmbeddingModelName,
10	  decodeFloat32Vector,
11	} from "@/lib/embeddingHealth";
12	import {
13	  buildConversationGeometry,
14	  buildYearEndConversationStats,
15	} from "@/lib/conversationGeometry";
16	import { founderDisplayName } from "@/lib/founderDisplay";
17	import { profilesForUpload } from "@/lib/methodologyProfiles";
18	import { canWrite } from "@/lib/roles";
19	
20	import ConversationGeometryPanel from "./ConversationGeometryPanel";
21	import MethodologyProfilesPanel from "./MethodologyProfilesPanel";
22	import SourceStructurePanel from "./SourceStructurePanel";
23	import TranscriptAnchorClient from "./TranscriptAnchorClient";
24	
25	export const dynamic = "force-dynamic";
26	
27	type Params = Promise<{ uploadId: string }>;
28	type SearchParams = Promise<{ error?: string }>;
29	
30	const STOPWORDS = new Set([
31	  "and",
32	  "are",
33	  "but",
34	  "for",
35	  "from",
36	  "have",
37	  "into",
38	  "not",
39	  "that",
40	  "the",
41	  "their",
42	  "this",
43	  "was",
44	  "with",
45	  "would",
46	]);
47	
48	function formatDate(value: Date): string {
49	  return new Intl.DateTimeFormat("en-US", {
50	    month: "short",
51	    day: "numeric",
52	    year: "numeric",
53	  }).format(value);
54	}
55	
56	function formatTimestamp(ms: number): string {
57	  const totalSeconds = Math.max(0, Math.floor(ms / 1000));
58	  const minutes = Math.floor(totalSeconds / 60);
59	  const seconds = totalSeconds % 60;
60	  return `${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
61	}
62	
63	function excerpt(text: string | null | undefined, max = 360): string {
64	  const cleaned = (text || "").replace(/\s+/g, " ").trim();
65	  if (cleaned.length <= max) return cleaned;
66	  return `${cleaned.slice(0, max - 3).trimEnd()}...`;
67	}
68	
69	function tokenize(text: string): Set<string> {
70	  return new Set(
71	    text
72	      .toLowerCase()
73	      .replace(/[^a-z0-9\s]/g, " ")
74	      .split(/\s+/)
75	      .filter((token) => token.length >= 3 && !STOPWORDS.has(token)),
76	  );
77	}
78	
79	function overlapScore(left: string, right: string): number {
80	  const a = tokenize(left);
81	  const b = tokenize(right);
82	  if (a.size === 0 || b.size === 0) return 0;
83	  let hits = 0;
84	  for (const token of b) {
85	    if (a.has(token)) hits++;
86	  }
87	  return hits / Math.sqrt(a.size);
88	}
89	
90	function cosine(left: number[], right: number[]): number | null {
91	  if (left.length !== right.length || left.length === 0) return null;
92	  let dot = 0;
93	  let leftNorm = 0;
94	  let rightNorm = 0;
95	  for (let index = 0; index < left.length; index++) {
96	    dot += left[index]! * right[index]!;
97	    leftNorm += left[index]! * left[index]!;
98	    rightNorm += right[index]! * right[index]!;
99	  }
100	  if (leftNorm === 0 || rightNorm === 0) return null;
101	  return dot / (Math.sqrt(leftNorm) * Math.sqrt(rightNorm));
102	}
103	
104	type SemanticChunkRow = {
105	  id: string;
106	  vector: unknown;
107	  dimension: number;
108	};
109	
110	type SemanticConclusionRow = {
111	  id: string;
112	  text: string;
113	  confidenceTier: string;
114	  topicHint: string;
115	  rationale: string;
116	  vector: unknown;
117	  dimension: number;
118	};
119	
120	async function semanticRelatedConclusions(organizationId: string, uploadId: string) {
121	  try {
122	    const modelName = await activeEmbeddingModelName();
123	    const [chunkRows, conclusionRows] = await Promise.all([
124	      db.$queryRaw<SemanticChunkRow[]>`
125	        SELECT uc.id, e.vector, e.dimension
126	        FROM "UploadChunk" uc
127	        INNER JOIN embedding e ON e.ref_claim_id = uc.id
128	        WHERE uc."uploadId" = ${uploadId}
129	          AND e.model_name = ${modelName}
130	      `,
131	      db.$queryRaw<SemanticConclusionRow[]>`
132	        SELECT c.id,
133	               c.text,
134	               c."confidenceTier",
135	               c."topicHint",
136	               c.rationale,
137	               e.vector,
138	               e.dimension
139	        FROM "Conclusion" c
140	        INNER JOIN embedding e ON e.ref_claim_id = c.id
141	        WHERE c."organizationId" = ${organizationId}
142	          AND e.model_name = ${modelName}
143	        ORDER BY c."createdAt" DESC
144	        LIMIT 200
145	      `,
146	    ]);
147	    const chunkVectors = chunkRows
148	      .map((row) => decodeFloat32Vector(row.vector, row.dimension))
149	      .filter((vector) => vector.length > 0);
150	    if (chunkVectors.length === 0 || conclusionRows.length === 0) return [];
151	
152	    return conclusionRows
153	      .map((row) => {
154	        const conclusionVector = decodeFloat32Vector(row.vector, row.dimension);
155	        const score = Math.max(
156	          0,
157	          ...chunkVectors
158	            .map((chunkVector) => cosine(chunkVector, conclusionVector))
159	            .filter((value): value is number => value !== null),
160	        );
161	        return { ...row, score };
162	      })
163	      .filter((row) => row.score > 0.18)
164	      .sort((a, b) => b.score - a.score || a.id.localeCompare(b.id))
165	      .slice(0, 5);
166	  } catch {
167	    return [];
168	  }
169	}
170	
171	async function relatedConclusions(organizationId: string, transcriptText: string, uploadId: string) {
172	  const semantic = await semanticRelatedConclusions(organizationId, uploadId);
173	  if (semantic.length > 0) return semantic;
174	
175	  const rows = await db.conclusion.findMany({
176	    where: { organizationId },
177	    orderBy: { createdAt: "desc" },
178	    take: 120,
179	    select: {
180	      id: true,
181	      text: true,
182	      confidenceTier: true,
183	      topicHint: true,
184	      rationale: true,
185	    },
186	  });
187	
188	  return rows
189	    .map((row) => ({
190	      ...row,
191	      score: overlapScore(row.text + " " + row.rationale + " " + row.topicHint, transcriptText),
192	    }))
193	    .filter((row) => row.score > 0)
194	    .sort((a, b) => b.score - a.score || a.id.localeCompare(b.id))
195	    .slice(0, 5);
196	}
197	
198	function sectionHeading(chunks: { id: string; headingHint: string | null }[]) {
199	  return chunks.filter((chunk) => chunk.headingHint?.trim()).map((chunk) => ({
200	    id: chunk.id,
201	    anchor: `chunk-${chunk.id}`,
202	    label: chunk.headingHint!.trim(),
203	  }));
204	}
205	
206	function isConversationLike(
207	  sourceType: string,
208	  chunks: { speakerLabel: string | null }[],
209	): boolean {
210	  const normalized = sourceType.trim().toLowerCase();
211	  if (["audio", "dialectic", "podcast", "session", "transcript"].includes(normalized)) {
212	    return true;
213	  }
214	  const speakers = new Set(
215	    chunks
216	      .map((chunk) => chunk.speakerLabel?.trim())
217	      .filter((speaker): speaker is string => Boolean(speaker)),
218	  );
219	  return speakers.size >= 2;
220	}
221	
222	export default async function TranscriptPage({
223	  params,
224	  searchParams,
225	}: {
226	  params: Params;
227	  searchParams: SearchParams;
228	}) {
229	  const founder = await getFounder();
230	  if (!founder) redirect("/login");
231	
232	  const { uploadId } = await params;
233	  const upload = await db.upload.findFirst({
234	    where: {
235	      id: uploadId,
236	      organizationId: founder.organizationId,
237	      deletedAt: null,
238	      OR: [{ visibility: { not: "private" } }, { founderId: founder.id }],
239	    },
240	    select: {
241	      id: true,
242	      title: true,
243	      description: true,
244	      sourceType: true,
245	      status: true,
246	      textContent: true,
247	      blurb: true,
248	      publishedAt: true,
249	      slug: true,
250	      visibility: true,
251	      createdAt: true,
252	      founderId: true,
253	      founder: { select: { displayName: true, name: true, username: true } },
254	      chunks: {
255	        orderBy: { index: "asc" },
256	        select: {
257	          id: true,
258	          index: true,
259	          text: true,
260	          startMs: true,
261	          endMs: true,
262	          speakerLabel: true,
263	          headingHint: true,
264	        },
265	      },
266	    },
267	  });
268	  if (!upload) notFound();
269	
270	  const sp = await searchParams;
271	  const displayChunks = upload.chunks.length
272	    ? upload.chunks
273	    : upload.textContent?.trim()
274	      ? [
275	          {
276	            id: "raw-text",
277	            index: 0,
278	            text: upload.textContent.trim(),
279	            startMs: null,
280	            endMs: null,
281	            speakerLabel: null,
282	            headingHint: null,
283	          },
284	        ]
285	      : [];
286	  const transcriptText =
287	    displayChunks.map((chunk) => chunk.text).join("\n\n") || upload.textContent || "";
288	  const headings = sectionHeading(displayChunks);
289	  const uploadYear = upload.createdAt.getUTCFullYear();
290	  const yearStart = new Date(Date.UTC(uploadYear, 0, 1));
291	  const yearEnd = new Date(Date.UTC(uploadYear + 1, 0, 1));
292	  const [related, yearUploads, methodologyProfiles] = await Promise.all([
293	    relatedConclusions(founder.organizationId, transcriptText, upload.id),
294	    db.upload.findMany({
295	      where: {
296	        organizationId: founder.organizationId,
297	        deletedAt: null,
298	        sourceType: { in: ["transcript", "audio"] },
299	        createdAt: { gte: yearStart, lt: yearEnd },
300	        OR: [{ visibility: { not: "private" } }, { founderId: founder.id }],
301	      },
302	      orderBy: { createdAt: "asc" },
303	      select: {
304	        id: true,
305	        title: true,
306	        createdAt: true,
307	        chunks: {
308	          orderBy: { index: "asc" },
309	          select: {
310	            id: true,
311	            index: true,
312	            text: true,
313	            startMs: true,
314	            endMs: true,
315	            speakerLabel: true,
316	          },
317	        },
318	      },
319	    }),
320	    profilesForUpload(founder.organizationId, upload.id),
321	  ]);
322	  const geometry = buildConversationGeometry(displayChunks);
323	  const conversationLike = isConversationLike(upload.sourceType, displayChunks);
324	  const yearStats = buildYearEndConversationStats(
325	    uploadYear,
326	    yearUploads.map((item) => ({
327	      id: item.id,
328	      title: item.title,
329	      createdAt: item.createdAt,
330	      chunks: item.chunks,
331	    })),
332	  );
333	  const writer = canWrite(founder.role);
