1	import { expect, test } from "@playwright/test";
2	import { PrismaClient } from "@prisma/client";
3	import { createSqlAdapter } from "../src/lib/prismaAdapter";
4	
5	const founderEmail = process.env.E2E_FOUNDER_EMAIL ?? process.env.SEED_FOUNDER_A_EMAIL;
6	const founderPassword =
7	  process.env.E2E_FOUNDER_PASSWORD ?? process.env.SEED_FOUNDER_A_PASSWORD;
8	const founderOrg = process.env.E2E_FOUNDER_ORG ?? "theseus-local";
9	
10	test("transcript anchor query scrolls to and highlights the target chunk", async ({ page }) => {
11	  test.skip(
12	    !process.env.DATABASE_URL || !founderEmail || !founderPassword,
13	    "DATABASE_URL and seeded founder credentials are required",
14	  );
15	
16	  const db = new PrismaClient({ adapter: createSqlAdapter() });
17	  const sourceId = `e2e-transcript-anchor-${Date.now()}`;
18	  let uploadId = "";
19	
20	  try {
21	    const org = await db.organization.findUnique({
22	      where: { slug: founderOrg },
23	      include: { founders: { where: { email: founderEmail! }, take: 1 } },
24	    });
25	    expect(org).toBeTruthy();
26	    const founder = org!.founders[0];
27	    expect(founder).toBeTruthy();
28	
29	    const upload = await db.upload.create({
30	      data: {
31	        organizationId: org!.id,
32	        founderId: founder!.id,
33	        title: `E2E Transcript Anchor ${sourceId}`,
34	        description: "E2E transcript anchor fixture.",
35	        sourceType: "transcript",
36	        originalName: `${sourceId}.txt`,
37	        mimeType: "text/plain",
38	        filePath: `/tmp/${sourceId}.txt`,
39	        fileSize: 512,
40	        textContent:
41	          "[00:00:12] Michael: The first line establishes the archive.\n" +
42	          "[00:01:30] Ada: The second line is the anchor target.\n" +
43	          "The final paragraph closes the fixture.",
44	        blurb:
45	          "A short fixture transcript used to verify that transcript anchors scroll to the correct line.",
46	        status: "ingested",
47	        visibility: "org",
48	        chunks: {
49	          create: [
50	            {
51	              index: 0,
52	              text: "The first line establishes the archive.",
53	              startMs: 12_000,
54	              speakerLabel: "Michael",
55	              headingHint: "Archive",
56	            },
57	            {
58	              index: 1,
59	              text: "The second line is the anchor target.",
60	              startMs: 90_000,
61	              speakerLabel: "Ada",
62	              headingHint: "Anchor Target",
63	            },
64	            {
65	              index: 2,
66	              text: "The final paragraph closes the fixture.",
67	            },
68	          ],
69	        },
70	      },
71	      include: { chunks: { orderBy: { index: "asc" } } },
72	    });
73	    uploadId = upload.id;
74	    const target = upload.chunks[1]!;
75	
76	    await page.context().clearCookies();
77	    await page.goto("/login");
78	    await page.getByLabel(/organization/i).fill(founderOrg);
79	    await page.getByLabel(/email/i).fill(founderEmail!);
80	    await page.getByLabel(/passphrase/i).fill(founderPassword!);
81	    await page.getByRole("button", { name: /enter the codex/i }).click();
82	    await page.waitForURL(/\/dashboard(?:\?|$)/, { timeout: 15_000 });
83	
84	    await page.goto(`/transcripts/${upload.id}?anchor=chunk-${target.id}`);
85	    const chunk = page.locator(`#chunk-${target.id}`);
86	    await expect(chunk).toBeVisible();
87	    await expect(page.getByRole("heading", { name: "Harvest table" })).toBeVisible();
88	    await expect(page.getByRole("button", { name: /Map/i })).toHaveAttribute("aria-pressed", "true");
89	    await page.getByRole("button", { name: /Catalysts/i }).click();
90	    await expect(page.getByText(/Catalyst scores rank adjacent speaker handoffs/i)).toBeVisible();
91	    await expect(page.getByText(/Neutral handoff \/ score/i)).toBeVisible();
92	    await expect(page.getByText("Source / Michael")).toBeVisible();
93	    await expect(page.getByText("Target / Ada")).toBeVisible();
94	    const catalystLink = page.getByRole("link", { name: "Michael -> Ada" });
95	    await expect(catalystLink).toBeVisible();
96	    await expect(catalystLink).toHaveAttribute(
97	      "href",
98	      `/transcripts/${upload.id}?anchor=chunk-${target.id}`,
99	    );
100	    await catalystLink.click();
101	    await expect(page).toHaveURL(new RegExp(`/transcripts/${upload.id}\\?anchor=chunk-${target.id}$`));
102	    await expect(chunk).toHaveClass(/chunk-highlight/);
103	    await expect
104	      .poll(async () =>
105	        chunk.evaluate((el) => {
106	          const rect = el.getBoundingClientRect();
107	          return rect.top >= 0 && rect.bottom <= window.innerHeight;
108	        }),
109	      )
110	      .toBe(true);
111	  } finally {
112	    if (uploadId) await db.upload.deleteMany({ where: { id: uploadId } });
113	    await db.$disconnect();
114	  }
115	});
