/* ═════════════════════════════════════════════════════════════════════════
 * Theseus Codex — unified globals source of truth
 *
 * This file now owns both the founder portal and the migrated public pages.
 * Public-site classes are scoped with `public-*`; generic public globals from
 * theseus-public are intentionally not imported.
 *
 * "Amber Oracle" aesthetic
 *
 * Terminal-inspired amber CRT on charcoal, classical Roman typography,
 * subtle scan-line phosphor glow. Text-first (EB Garamond for body,
 * Cinzel for display), monospace (IBM Plex Mono) for numeric / terminal
 * accents, with box-drawing characters as UI chrome.
 *
 * Palette shift from prior version: gold-amber is now the dominant accent
 * with a stronger CRT-orange fallback (`--amber`), and the whole UI sits
 * over a near-black charcoal rather than warm stone, so the phosphor glow
 * actually looks like phosphor.
 *
 * Scan-line overlay + amber vignette are provided by <CRTOverlay /> in
 * the root layout — don't add them here so they can be disabled per-user
 * via prefers-reduced-motion or a future user preference.
 * ═════════════════════════════════════════════════════════════════════════ */

@import url('https://fonts.googleapis.com/css2?family=EB+Garamond:ital,wght@0,400;0,500;0,600;1,400;1,500&family=Cinzel:wght@400;500;600;700&family=Cinzel+Decorative:wght@400;700&family=Inter:wght@300;400;500&family=IBM+Plex+Mono:ital,wght@0,300;0,400;0,500;0,600;1,400&display=swap');
@import "tailwindcss";

/* ── Theseus Design Tokens — Amber Oracle ────────────────────────────────── */

:root {
  color-scheme: dark;
  --ink:          var(--stone);  /* codex-origin: public-site background alias */
  --stone:        #08070a;   /* codex-origin: void background */
  --stone-light:  #120f0b;   /* codex-origin: card surfaces */
  --stone-mid:    #1b1612;   /* codex-origin: raised/input surfaces */
  --amber:        #e9a338;   /* codex-origin: links, active nav, highlights */
  --amber-dim:    #a8762a;   /* codex-origin: metadata and quiet accents */
  --amber-deep:   #5e4617;   /* codex-origin: disabled/subtle borders */
  --amber-glow:   rgba(233, 163, 56, 0.35);  /* codex-origin: drop-shadows */
  --parchment:    #efe2c7;   /* codex-origin: primary readable foreground */
  --parchment-dim:#9c8f72;   /* codex-origin: secondary readable foreground */
  --gold:         var(--amber);      /* codex-origin: legacy alias */
  --gold-dim:     var(--amber-dim);  /* codex-origin: legacy alias */
  --ember:        #c94a1f;   /* codex-origin: error/action heat */
  --border:       #3a2d12;   /* codex-origin: kept over public --border conflict */
  --success:      #7ea83a;   /* codex-origin: success state */
  --info:         #3a7aa8;   /* codex-origin: informational state */
  --glow-sm: 0 0 6px var(--amber-glow);  /* codex-origin: small phosphor glow */
  --glow-md: 0 0 14px var(--amber-glow), 0 0 2px var(--amber);  /* codex-origin: medium phosphor glow */
  --glow-lg: 0 0 28px var(--amber-glow), 0 0 4px var(--amber);  /* codex-origin: large phosphor glow */
}

[data-theme="light"] {
  color-scheme: light;
  --ink:          var(--stone);  /* codex-origin light: public-site background alias */
  --stone:        #f2e8d9;   /* codex-origin light: parchment background */
  --stone-light:  #ede0cc;   /* codex-origin light: card surfaces */
  --stone-mid:    #e4d4ba;   /* codex-origin light: raised/input surfaces */
  --amber:        #7a5218;   /* codex-origin light: links and highlights */
  --amber-dim:    #9a6c28;   /* codex-origin light: metadata and quiet accents */
  --amber-deep:   #c1a670;   /* codex-origin light: disabled/subtle borders */
  --amber-glow:   rgba(122, 82, 24, 0.18);  /* codex-origin light: drop-shadows */
  --parchment:    #2a2318;   /* codex-origin light: primary foreground */
  --parchment-dim:#5a4e3a;   /* codex-origin light: secondary foreground */
  --gold:         var(--amber);      /* codex-origin light: legacy alias */
  --gold-dim:     var(--amber-dim);  /* codex-origin light: legacy alias */
  --ember:        #8b3a2a;   /* codex-origin light: error/action heat */
  --border:       #cbbfa8;   /* codex-origin light: kept over public --border conflict */
  --success:      #3a6a2a;   /* codex-origin light: success state */
  --info:         #2a4a6a;   /* codex-origin light: informational state */
  --glow-sm: 0 0 6px var(--amber-glow);  /* codex-origin light: small phosphor glow */
  --glow-md: 0 0 14px var(--amber-glow);  /* codex-origin light: medium glow */
  --glow-lg: 0 0 22px var(--amber-glow);  /* codex-origin light: large glow */
}

html { transition: background 0.25s, color 0.25s; }

@theme inline {
  --color-background: var(--stone);      /* codex-origin: Tailwind background mapping */
  --color-foreground: var(--parchment);  /* codex-origin: Tailwind foreground mapping */
}

* { box-sizing: border-box; }

html, html[data-theme] {
  background-color: var(--stone);
  color: var(--parchment);
}

body {
  background-color: var(--stone);
  color: var(--parchment);
  font-family: 'EB Garamond', Georgia, serif;
  font-size: 17px;
  line-height: 1.7;
  min-height: 100vh;
  /* Faint amber tint on body text itself, so the whole UI feels bathed in
     phosphor. Not so strong that body text becomes hard to read. */
  text-shadow: 0 0 1px rgba(233, 163, 56, 0.05);
}

.skip-link {
  background: var(--amber);
  border: 1px solid var(--parchment);
  box-shadow: 0 0 0 2px var(--stone), var(--glow-sm);
  color: var(--stone);
  font-family: "IBM Plex Mono", monospace;
  font-size: 0.75rem;
  font-weight: 700;
  left: 1rem;
  letter-spacing: 0.12em;
  padding: 0.55rem 0.75rem;
  position: fixed;
  text-decoration: none;
  text-transform: uppercase;
  top: 0.75rem;
  transform: translateY(-160%);
  transition: transform 160ms ease;
  z-index: 10000;
}

.skip-link:focus,
.skip-link:focus-visible {
  outline: 2px solid var(--parchment);
  outline-offset: 2px;
  transform: translateY(0);
}

.skip-link:focus:not(:focus-visible) {
  transform: translateY(-160%);
}

#main-content:focus,
[data-skip-focus-target]:focus {
  outline: none;
}

@media (prefers-reduced-motion: reduce) {
  .skip-link {
    transition: none;
  }
}

h1, h2, h3, h4 {
  font-family: 'Cinzel', 'Palatino Linotype', serif;
  font-weight: 500;
  letter-spacing: 0.05em;
}

/* ── Mono utility class for terminal-style text (timestamps, IDs, numbers) ── */
.mono, code, pre, kbd {
  font-family: 'IBM Plex Mono', 'JetBrains Mono', Menlo, monospace;
  font-feature-settings: "tnum" 1, "ss01" 1;  /* tabular figures */
}

/* ── Scrollbar — CRT-thin, amber on hover ───────────────────────────────── */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: var(--stone); }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--amber-dim); }
::selection { background: var(--amber-dim); color: var(--stone); text-shadow: none; }

/* ── Form elements ───────────────────────────────────────────────────────── */
input, textarea, select {
  background: var(--stone-mid);
  border: 1px solid var(--border);
  color: var(--parchment);
  font-family: 'EB Garamond', Georgia, serif;
  font-size: 1rem;
  padding: 0.6rem 0.9rem;
  border-radius: 2px;
  outline: none;
  transition: border-color 0.2s, box-shadow 0.2s;
  width: 100%;
}

input:focus, textarea:focus, select:focus {
  border-color: var(--amber);
  box-shadow: var(--glow-sm);
}

input::placeholder, textarea::placeholder {
  color: var(--parchment-dim);
  opacity: 0.5;
}

/* ── Buttons — amber with phosphor glow on hover ─────────────────────────── */
.btn {
  font-family: 'Cinzel', serif;
  font-size: 0.75rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  padding: 0.6rem 1.4rem;
  border: 1px solid var(--amber-dim);
  background: transparent;
  color: var(--amber);
  cursor: pointer;
  transition: all 0.2s;
  border-radius: 1px;
  text-shadow: 0 0 1px var(--amber-glow);
}

.btn:hover {
  background: var(--amber-dim);
  color: var(--stone);
  box-shadow: var(--glow-md);
  text-shadow: none;
}

.btn:focus-visible {
  outline: none;
  box-shadow: var(--glow-lg);
}

.btn-solid {
  background: var(--amber-dim);
  color: var(--stone);
  border-color: var(--amber-dim);
  text-shadow: none;
}

.btn-solid:hover {
  background: var(--amber);
  border-color: var(--amber);
  box-shadow: var(--glow-lg);
}

/* ── Cards ───────────────────────────────────────────────────────────────── */
.portal-card {
  background: var(--stone-light);
  border: 1px solid var(--border);
  border-radius: 2px;
  padding: 1.5rem;
  transition: border-color 0.2s, box-shadow 0.2s, transform 0.15s;
  position: relative;
}

.portal-card:hover {
  border-color: var(--amber-dim);
  box-shadow: var(--glow-sm);
}

/* ── Migrated public publication pages ─────────────────────────────────────
 * These are prefixed ports of theseus-public's `.container`, `.card`,
 * `.muted`, and `.hr` utilities. They use Codex-origin tokens rather than
 * reintroducing the old public global variables.
 */
.public-container {
  max-width: 860px;
  margin: 0 auto;
  padding: 2.25rem 1.25rem 4rem;
  position: relative;
  z-index: 1;
}

.public-container a {
  color: var(--amber);
}

.public-title {
  font-family: 'EB Garamond', 'Iowan Old Style', Georgia, serif;
  font-size: clamp(1.85rem, 4.4vw, 2.6rem);
  font-weight: 600;
  letter-spacing: -0.005em;
  line-height: 1.18;
  margin: 0;
  color: var(--amber);
  text-shadow: var(--glow-sm);
}

.public-article-body {
  text-align: justify;
  text-justify: inter-word;
  hyphens: auto;
  -webkit-hyphens: auto;
  hyphenate-limit-chars: 6 3 3;
  hyphenate-limit-lines: 2;
  text-wrap: pretty;
  max-width: 70ch;
}

.public-article-body :where(ul, ol, li, blockquote, pre, code, table) {
  text-align: start;
  hyphens: manual;
  -webkit-hyphens: manual;
}

.public-lede {
  max-width: 75ch;
  margin-top: 0.85rem;
  font-size: 1rem;
}

.public-muted {
  color: var(--parchment-dim);
}

.public-kicker {
  margin-top: 0;
  font-size: 0.85rem;
}

.public-card {
  border: 1px solid var(--border);
  background: var(--stone-light);
  border-radius: 2px;
  padding: 1rem 1.1rem;
  margin-top: 0.75rem;
}

.public-card h2,
.public-section h2 {
  font-size: 1rem;
  margin: 0;
  color: var(--amber);
}

.public-card p {
  margin: 0.65rem 0 0;
}

.public-section {
  margin-top: 1.25rem;
}

.public-section-heading {
  align-items: baseline;
  display: flex;
  flex-wrap: wrap;
  gap: 0.6rem 1rem;
  justify-content: space-between;
}

.public-section-link {
  border: 1px solid var(--amber-deep);
  color: var(--amber);
  font-size: 0.62rem;
  letter-spacing: 0.16em;
  padding: 0.34rem 0.5rem;
  text-decoration: none;
  text-transform: uppercase;
}

.public-section-link:focus-visible {
  outline: 2px solid var(--amber);
  outline-offset: 3px;
}

.public-section p {
  max-width: 75ch;
  margin: 0.5rem 0 0;
}

.public-section ul,
.public-section ol {
  margin: 0.6rem 0 0;
  padding-left: 1.2rem;
}

.public-section li {
  margin: 0.35rem 0;
}

.public-method-grid {
  display: grid;
  gap: 0.85rem;
  grid-template-columns: repeat(auto-fit, minmax(min(100%, 240px), 1fr));
  margin-top: 0.85rem;
}

.public-method-split {
  display: grid;
  gap: 0.85rem;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  margin-top: 0.85rem;
}

.public-method-card {
  display: grid;
  gap: 0.65rem;
  margin-top: 0;
  min-width: 0;
}

.public-method-card h3 {
  color: var(--amber);
  font-size: 0.95rem;
  line-height: 1.25;
  margin: 0;
}

.public-method-card p {
  margin: 0;
}

.public-method-meta {
  align-items: center;
  color: var(--amber-dim);
  display: flex;
  flex-wrap: wrap;
  font-size: 0.58rem;
  gap: 0.4rem 0.65rem;
  justify-content: space-between;
  letter-spacing: 0.16em;
  text-transform: uppercase;
}

.public-method-summary {
  color: var(--parchment);
  font-size: 0.95rem;
  line-height: 1.5;
}

.public-method-note {
  background: rgba(232, 225, 211, 0.035);
  color: var(--parchment-dim);
}

.public-method-note.public-card {
  margin-top: 0.75rem;
}

.public-method-note p {
  margin: 0;
}

.public-method-narrative {
  color: var(--parchment);
}

.public-method-list-group {
  border-top: 1px solid rgba(232, 225, 211, 0.1);
  padding-top: 0.6rem;
}

.public-method-list-group h4 {
  color: var(--parchment-dim);
  font-size: 0.58rem;
  letter-spacing: 0.16em;
  margin: 0 0 0.35rem;
  text-transform: uppercase;
}

.public-method-list {
  display: grid;
  gap: 0.28rem;
  list-style: none;
  margin: 0;
  padding: 0;
}

.public-method-list li {
  color: var(--parchment-dim);
  font-size: 0.9rem;
  line-height: 1.45;
  margin: 0;
  padding-left: 0.85rem;
  position: relative;
}

.public-method-list li::before {
  background: var(--amber-dim);
  content: "";
  height: 0.28rem;
  left: 0;
  position: absolute;
  top: 0.58rem;
  width: 0.28rem;
}

.public-hr {
  height: 1px;
  background: var(--border);
  border: 0;
  margin: 1.25rem 0;
}

.public-inline-stat {
  margin-left: 0.65rem;
}

.public-citation {
  margin-top: 0.85rem;
}

.public-citation-head {
  display: flex;
  justify-content: space-between;
  gap: 0.75rem;
  align-items: center;
}

.public-citation-head .mono {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.public-pre {
  margin-top: 0.5rem;
  padding: 0.75rem;
  border: 1px solid var(--border);
  border-radius: 2px;
  overflow-x: auto;
  font-size: 0.85rem;
  background: var(--stone-mid);
  color: var(--parchment);
  white-space: pre;
}

.public-section .public-response-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.public-section .public-response-list .mono {
  font-size: 0.8rem;
}

.public-section .firm-source-list {
  list-style: decimal;
  margin: 0.55rem 0 0;
  padding-left: 1.15rem;
}

.firm-source-row {
  border-bottom: 1px dashed var(--border);
  box-shadow: none;
  color: var(--parchment);
  line-height: 1.5;
  margin: 0;
  padding: 0.45rem 0;
  overflow-wrap: anywhere;
}

.firm-source-row:last-child {
  border-bottom: 0;
}

.firm-source-row a,
.firm-source-row span {
  display: block;
}

.firm-source-row a {
  color: var(--amber);
  text-decoration-color: rgba(210, 163, 73, 0.45);
  text-underline-offset: 0.18em;
}

.firm-source-row .mono {
  color: var(--parchment-dim);
  display: block;
  font-size: 0.68rem;
  letter-spacing: 0.08em;
  margin-top: 0.18rem;
}

.public-footer-link {
  margin-top: 1.75rem;
}

.public-form-card {
  margin-top: 1.25rem;
}

.public-label {
  color: var(--parchment-dim);
  font-size: 0.9rem;
  display: block;
  margin-top: 0.75rem;
}

.public-label input,
.public-label select,
.public-label textarea {
  display: block;
  width: 100%;
  margin-top: 0.35rem;
}

.public-field-error {
  color: var(--ember);
  font-family: 'IBM Plex Mono', monospace;
  font-size: 0.72rem;
  line-height: 1.45;
  margin: -0.35rem 0 0;
}

.public-form-status {
  color: var(--amber);
  font-family: 'IBM Plex Mono', monospace;
  font-size: 0.76rem;
  min-height: 1.4rem;
}

.btn:disabled,
.btn:disabled:hover {
  background: transparent;
  border-color: var(--amber-deep);
  box-shadow: none;
  color: var(--parchment-dim);
  /* "Not ready" cursor. The in-flight (loading) treatment uses wait
     via .btn--loading below; keeping them visually distinct is the
     Round 20 contract requirement. */
  cursor: not-allowed;
}

/* ── Button variants (Round 20) ──────────────────────────────────────────
 * The default `.btn` (Cinzel uppercase) reads as ceremonial. For dense
 * workflow surfaces we expose two quieter variants — `quiet` and
 * `ghost` — that share size/hit-target with `.btn` but drop the
 * theatrical tracking and font.
 *
 * Variants are additive: `<button class="btn btn--quiet">…</button>`
 * keeps the focus ring and disabled treatment from `.btn`.
 */
.btn--default { /* explicit alias for the original .btn appearance */ }

.btn--quiet {
  font-family: 'Inter', 'EB Garamond', Georgia, serif;
  font-size: 0.78rem;
  font-weight: 500;
  letter-spacing: 0.02em;
  text-transform: none;
  padding: 0.45rem 0.95rem;
  border-color: var(--border);
  color: var(--parchment);
  text-shadow: none;
}

.btn--quiet:hover {
  background: var(--stone-mid);
  border-color: var(--amber-dim);
  color: var(--amber);
  box-shadow: none;
}

.btn--ghost {
  font-family: 'Inter', 'EB Garamond', Georgia, serif;
  font-size: 0.78rem;
  font-weight: 500;
  letter-spacing: 0.02em;
  text-transform: none;
  padding: 0.35rem 0.6rem;
  border-color: transparent;
  background: transparent;
  color: var(--amber);
  text-shadow: none;
}

.btn--ghost:hover {
  background: rgba(233, 163, 56, 0.08);
  border-color: transparent;
  color: var(--amber);
  box-shadow: none;
}

.btn--sm {
  font-size: 0.7rem;
  padding: 0.3rem 0.7rem;
}

.btn--solid,
.btn-solid {
  background: var(--amber-dim);
  color: var(--stone);
  border-color: var(--amber-dim);
  text-shadow: none;
}

.btn--solid:hover,
.btn-solid:hover {
  background: var(--amber);
  border-color: var(--amber);
  box-shadow: var(--glow-lg);
}

/* ── Button states (loading / success / error) ───────────────────────────
 * Three additive modifiers on top of any variant. They communicate the
 * outcome of the action without removing the button from the DOM, which
 * matters for re-tries and for screen-reader continuity (the live region
 * for `aria-busy` is the button itself).
 */
.btn--loading {
  position: relative;
  cursor: wait;
  /* Slight desaturation so the user can see the action is "in flight"
     rather than just "disabled". */
  color: var(--amber-dim);
  border-color: var(--amber-dim);
}

.btn--loading .btn-label {
  opacity: 0.7;
}

.btn-spinner {
  display: inline-block;
  width: 0.78em;
  height: 0.78em;
  margin-right: 0.5em;
  border: 1.5px solid currentColor;
  border-right-color: transparent;
  border-radius: 50%;
  vertical-align: -0.12em;
  animation: btn-spin 0.7s linear infinite;
}

@keyframes btn-spin {
  to { transform: rotate(360deg); }
}

@media (prefers-reduced-motion: reduce) {
  .btn-spinner { animation: none; opacity: 0.65; }
}

.btn--success {
  border-color: var(--success);
  color: var(--success);
  background: transparent;
}

.btn--success:hover {
  background: rgba(126, 168, 58, 0.1);
  border-color: var(--success);
  color: var(--success);
  box-shadow: none;
}

.btn--success .btn-glyph {
  margin-right: 0.45em;
  font-weight: 600;
}

.btn--error {
  border-color: var(--ember);
  color: var(--ember);
  background: transparent;
}

.btn--error:hover {
  background: rgba(201, 74, 31, 0.1);
  border-color: var(--ember);
  color: var(--ember);
  box-shadow: none;
}

.btn[aria-busy="true"] {
  cursor: wait;
}

/* Anchors styled like .btn inherit disabled visuals via [aria-disabled]. */
.btn[aria-disabled="true"],
.btn[aria-disabled="true"]:hover {
  background: transparent;
  border-color: var(--amber-deep);
  box-shadow: none;
  color: var(--parchment-dim);
  cursor: not-allowed;
  pointer-events: none;
}

/* ── Page header (compact, authenticated) ────────────────────────────────
 * Use on workflow surfaces where the heading needs to be visible but
 * should not dominate the first viewport. Operational sibling to
 * `PageHelp` (and to public `.public-title`).
 */
.page-header {
  align-items: flex-start;
  display: flex;
  flex-wrap: wrap;
  gap: 0.85rem 1.5rem;
  justify-content: space-between;
  margin: 0 0 1.25rem;
}

.page-header__lead {
  min-width: 0;
  flex: 1 1 22rem;
}

.page-header__kicker {
  color: var(--amber-dim);
  font-family: 'IBM Plex Mono', monospace;
  font-size: 0.6rem;
  letter-spacing: 0.16em;
  margin: 0 0 0.3rem;
  text-transform: uppercase;
}

.page-header__title {
  color: var(--amber);
  font-family: 'Cinzel', serif;
  font-size: 1.45rem;
  font-weight: 500;
  letter-spacing: 0.06em;
  line-height: 1.2;
  margin: 0;
  text-shadow: var(--glow-sm);
}

.page-header__desc {
  color: var(--parchment-dim);
  font-family: 'EB Garamond', Georgia, serif;
  font-size: 1rem;
  font-style: normal;
  line-height: 1.55;
  margin: 0.45rem 0 0;
  max-width: 64ch;
}

.page-header__actions {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

@media (max-width: 720px) {
  .page-header__title { font-size: 1.25rem; letter-spacing: 0.04em; }
}

/* ── Section header (in-page grouping) ───────────────────────────────────
 * Used inside cards/sections. Tracking is reserved for the *kicker* —
 * the heading itself stays close to body proportions.
 */
.section-header {
  align-items: flex-end;
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 1rem;
  justify-content: space-between;
  margin: 0 0 0.75rem;
}

.section-header__lead { min-width: 0; flex: 1 1 18rem; }

.section-header__kicker {
  color: var(--amber-dim);
  display: block;
  font-size: 0.58rem;
  letter-spacing: 0.18em;
  margin: 0 0 0.2rem;
  text-transform: uppercase;
}

.section-header__title {
  color: var(--amber);
  font-family: 'Cinzel', serif;
  font-size: 1.02rem;
  font-weight: 500;
  letter-spacing: 0.04em;
  line-height: 1.25;
  margin: 0;
}

.section-header__hint {
  color: var(--parchment-dim);
  font-size: 0.85rem;
  line-height: 1.45;
  margin: 0.3rem 0 0;
  max-width: 60ch;
}

.section-header__actions {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
}

/* ── Action row ──────────────────────────────────────────────────────────
 * Group of inline actions (buttons/links). Wraps before causing
 * horizontal overflow.
 */
.action-row {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.6rem;
  justify-content: flex-end;
  margin: 0;
}

.action-row--start { justify-content: flex-start; }
.action-row--between { justify-content: space-between; }
.action-row--gap-sm { gap: 0.35rem; }

/* ── Status pill (quiet, inline) ─────────────────────────────────────────
 * Sibling to `.badge-*` but smaller and lower contrast — for inline
 * metadata next to a title.
 */
.status-pill {
  align-items: center;
  border: 1px solid var(--border);
  border-radius: 999px;
  color: var(--parchment-dim);
  display: inline-flex;
  font-family: 'IBM Plex Mono', monospace;
  font-size: 0.6rem;
  gap: 0.3rem;
  letter-spacing: 0.1em;
  line-height: 1;
  padding: 0.18rem 0.5rem;
  text-transform: uppercase;
  vertical-align: middle;
}

.status-pill--neutral { color: var(--parchment-dim); border-color: var(--border); }
.status-pill--info    { color: var(--info);          border-color: var(--info); }
.status-pill--success { color: var(--success);       border-color: var(--success); }
.status-pill--warning { color: var(--amber);         border-color: var(--amber-dim); }
.status-pill--danger  { color: var(--ember);         border-color: var(--ember); }

/* ── Top nav (founder shell) — responsive vocabulary ─────────────────────
 * Round 20 moves the founder nav off inline styles. The CSS lives here
 * so it can collapse cleanly at narrow widths without `Nav.tsx`
 * carrying breakpoint logic.
 *
 *   .nav-shell        sticky bar
 *   .nav-shell__inner content row, wraps before overflow
 *   .nav-shell__brand wordmark + labyrinth
 *   .nav-shell__links primary route links
 *   .nav-shell__meta  account/help/theme/sign-out cluster
 */
.nav-shell {
  background: var(--stone);
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 50;
}

.nav-shell__inner {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.6rem 1.25rem;
  justify-content: space-between;
  margin: 0 auto;
  max-width: 1200px;
  min-height: 64px;
  padding: 0.85rem 1rem;
}

.nav-shell__brand {
  align-items: center;
  color: var(--amber);
  display: inline-flex;
  font-family: 'Cinzel', serif;
  font-size: 0.95rem;
  font-weight: 600;
  gap: 0.5rem;
  letter-spacing: 0.18em;
  text-decoration: none;
  text-shadow: var(--glow-sm);
}

.nav-shell__links {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem 1.1rem;
  justify-content: center;
  min-width: 0;
}

.nav-shell__link {
  align-items: center;
  color: var(--parchment-dim);
  display: inline-flex;
  font-family: 'Cinzel', serif;
  font-size: 0.7rem;
  gap: 0.35rem;
  letter-spacing: 0.1em;
  padding: 0.3rem 0.1rem;
  text-decoration: none;
  text-transform: uppercase;
  transition: color 0.15s ease, border-color 0.15s ease;
  border-bottom: 1px solid transparent;
}

.nav-shell__link:hover { color: var(--amber); }

.nav-shell__link[aria-current="page"] {
  color: var(--amber);
  border-bottom-color: var(--amber-dim);
}

.nav-shell__meta {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 0.8rem;
  justify-content: flex-end;
}

.nav-shell__help,
.nav-shell__account {
  color: var(--parchment-dim);
  font-family: 'Cinzel', serif;
  font-size: 0.62rem;
  letter-spacing: 0.1em;
  text-decoration: none;
  text-transform: uppercase;
  transition: color 0.15s ease;
}

.nav-shell__help:hover,
.nav-shell__account:hover {
  color: var(--amber);
}

.nav-shell__account-org {
  color: var(--parchment-dim);
  margin-left: 0.35rem;
}

.nav-shell__signout {
  font-size: 0.6rem;
  padding: 0.3rem 0.75rem;
}

@media (max-width: 900px) {
  .nav-shell__inner { gap: 0.5rem 0.75rem; }
  .nav-shell__links { gap: 0.3rem 0.7rem; }
  .nav-shell__link  { font-size: 0.66rem; letter-spacing: 0.08em; }
}

@media (max-width: 640px) {
  .nav-shell__inner { padding: 0.7rem 0.85rem; }
  .nav-shell__account-org { display: none; }
}

.public-checkbox {
  color: var(--parchment-dim);
  display: flex;
  gap: 0.5rem;
  align-items: center;
  margin-top: 0.75rem;
}

.public-checkbox input {
  width: auto;
}

@media (max-width: 720px) {
  .public-container {
    padding: 1.75rem 1rem 3.5rem;
  }

  .public-method-split {
    grid-template-columns: 1fr;
  }

  .public-section-heading {
    align-items: flex-start;
    flex-direction: column;
  }

  .public-inline-stat {
    display: block;
    margin-left: 0;
    margin-top: 0.35rem;
  }

  .public-citation-head {
    align-items: flex-start;
    flex-direction: column;
  }
}

/* ── Upload zone ─────────────────────────────────────────────────────────── */
.upload-zone {
  border: 2px dashed var(--border);
  border-radius: 2px;
  padding: 3rem 2rem;
  text-align: center;
  transition: all 0.2s;
  cursor: pointer;
}

.upload-zone:hover, .upload-zone.dragover {
  border-color: var(--amber);
  background: var(--stone-light);
  box-shadow: var(--glow-md);
}

/* ── Status badges ───────────────────────────────────────────────────────── */
.badge {
  font-family: 'IBM Plex Mono', monospace;
  font-size: 0.65rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 0.2rem 0.6rem;
  border-radius: 1px;
  display: inline-block;
}

.badge-pending    { background: var(--stone-mid); color: var(--parchment-dim); border: 1px solid var(--border); }
.badge-processing { background: transparent; color: var(--info); border: 1px solid var(--info); }
.badge-ingested   { background: transparent; color: var(--success); border: 1px solid var(--success); }
.badge-failed     { background: transparent; color: var(--ember); border: 1px solid var(--ember); box-shadow: 0 0 4px rgba(201, 74, 31, 0.4); }

/* ── Stat card ───────────────────────────────────────────────────────────── */
.stat-card {
  background: var(--stone-light);
  border: 1px solid var(--border);
  border-radius: 2px;
  padding: 1.2rem;
  text-align: center;
}

.stat-value {
  font-family: 'Cinzel', serif;
  font-size: 2rem;
  color: var(--amber);
  font-weight: 500;
  text-shadow: var(--glow-sm);
}

.stat-label {
  font-family: 'IBM Plex Mono', monospace;
  font-size: 0.65rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--parchment-dim);
  margin-top: 0.3rem;
}

/* ── Ornament & classical flourishes ─────────────────────────────────────── */
.ornament::before {
  content: '— ✦ —';
  color: var(--amber-dim);
  font-family: 'Cinzel', serif;
  font-size: 0.75rem;
  letter-spacing: 0.3em;
}

/* Greek-key (meander) divider, SVG-based, can be applied to any hr or div.
   Renders as a repeating pattern across the full container width. */
.meander {
  height: 18px;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 36 18' preserveAspectRatio='xMinYMin slice'><path d='M0 4 L12 4 L12 14 L24 14 L24 4 L36 4' fill='none' stroke='%23a8762a' stroke-width='1' stroke-linecap='square' stroke-linejoin='miter'/></svg>");
  background-repeat: repeat-x;
  background-size: 36px 18px;
  border: 0;
  opacity: 0.7;
  margin: 1.5rem 0;
}

/* Box-drawing-character ascii frame. Applied via:
     <div class="ascii-frame" data-label="CORNER TAG">...</div>
   The ::before and ::after render the corner characters at top-left and
   bottom-right; the data-label becomes a small label inset into the top
   border, like a UI panel from a 1980s terminal. */
.ascii-frame {
  position: relative;
  border: 1px solid var(--amber-dim);
  padding: 1.25rem 1.5rem;
  font-family: inherit;
  background: var(--stone-light);
  /* subtle inner glow as if the frame is lit from behind */
  box-shadow: inset 0 0 24px rgba(233, 163, 56, 0.03);
}

.ascii-frame::before {
  content: '╔';
  position: absolute;
  top: -11px; left: -7px;
  color: var(--amber-dim);
  font-family: 'IBM Plex Mono', monospace;
  font-size: 1rem;
  background: var(--stone);
  padding: 0 2px;
  line-height: 1;
}

.ascii-frame::after {
  content: '╝';
  position: absolute;
  bottom: -11px; right: -7px;
  color: var(--amber-dim);
  font-family: 'IBM Plex Mono', monospace;
  font-size: 1rem;
  background: var(--stone);
  padding: 0 2px;
  line-height: 1;
}

.ascii-frame[data-label]::before {
  content: '╔═══ ' attr(data-label) ' ';
  padding: 0 6px 0 4px;
  letter-spacing: 0.1em;
  font-size: 0.7rem;
  color: var(--amber-dim);
}

/* Amber glow utility — apply to any element that should look "lit". */
.glow-sm { box-shadow: var(--glow-sm); }
.glow-md { box-shadow: var(--glow-md); }
.glow-lg { box-shadow: var(--glow-lg); }
.text-glow { text-shadow: 0 0 8px var(--amber-glow), 0 0 2px var(--amber); }

/* Blinking cursor utility — put `<span class="cursor">_</span>` after any
   heading that should feel like a live terminal prompt. */
.cursor::after {
  content: '_';
  display: inline-block;
  margin-left: 4px;
  color: var(--amber);
  animation: cursor-blink 1.05s steps(1) infinite;
  text-shadow: var(--glow-sm);
}

@keyframes cursor-blink {
  0%, 49% { opacity: 1; }
  50%, 100% { opacity: 0; }
}

/* ── Page entrance animations ────────────────────────────────────────────── */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

.fade-up { animation: fadeUp 0.4s ease forwards; }

/* "Type in" flicker — content briefly flickers on first paint, like CRT
   phosphor warming up. Only runs on load; disabled by prefers-reduced-motion. */
@keyframes crt-flicker {
  0% { opacity: 0.6; }
  5% { opacity: 0.95; }
  10% { opacity: 0.7; }
  15% { opacity: 1; }
  100% { opacity: 1; }
}

.crt-fade-in {
  animation: crt-flicker 0.9s ease-out forwards;
}

@media (prefers-reduced-motion: reduce) {
  .crt-fade-in,
  .cursor::after,
  .fade-up,
  .gate-labyrinth,
  .gate-pulse,
  .crt-noise { animation: none !important; }
  /* Note: .gate-leave / .gate-hairline / .codex-arrival /
     .codex-arrival-hairline are also disabled by the later @media block
     at the end of this section. Listed here for discoverability. */
}

/* ── Amber noise drift ──────────────────────────────────────────────────
 * The `<CRTOverlay />` amber-noise layer wallpapers a 256px tile across
 * the viewport and drifts the background-position very slowly (48s cycle
 * for 256px travel = ~5px/s). Slow enough to be subliminal; present enough
 * that the page feels alive rather than a flat render. */
.crt-noise {
  animation: crt-noise-drift 48s linear infinite;
}

/* ── Light-mode CRT overlay dampening ─────────────────────────────────────
 *
 * The CRT noise + darkening vignette are the signature "amber oracle"
 * effect in dark mode. In light mode they'd fight the bright
 * parchment background instead: the noise layer is a dark amber
 * pattern at mix-blend-mode `screen` (designed for a black base) —
 * over parchment it just muddies the page. And the vignette
 * darkens the rim of a page that's supposed to read as ink-on-paper.
 *
 * Both get suppressed here. If a user ever wants the CRT feel back
 * they can flip `data-theme` to dark.
 */
[data-theme="light"] .crt-noise {
  display: none;
}

[data-theme="light"] .crt-vignette {
  /* A whisper of darkening at the corners keeps the reading page
   * from feeling flat, without looking like an old monitor. */
  background: radial-gradient(
    ellipse at center,
    transparent 70%,
    rgba(90, 78, 58, 0.10) 100%
  ) !important;
}

/* Dark mode is the default — explicit selector keeps the cascade
 * readable when we inspect in devtools. */
[data-theme="dark"] .crt-noise {
  display: block;
}

@keyframes crt-noise-drift {
  0%   { background-position: 0 0; }
  100% { background-position: 256px 256px; }
}

/* ── Gate (/) animations ─────────────────────────────────────────────────── */

/* Idle state: the labyrinth rotates *slowly* (90s full turn) plus a subtle
   4s amber breath via drop-shadow intensity. The rotation is slow enough to
   feel like a ritual object, not a spinner. */
.gate-labyrinth {
  display: inline-block;
  animation: gate-spin-slow 90s linear infinite;
  color: var(--amber);
}

.gate-pulse {
  animation: gate-spin-slow 90s linear infinite, gate-breath 4.5s ease-in-out infinite;
}

/*
 * TRANSITION ANIMATION (login → dashboard) — minimalist rewrite
 * ─────────────────────────────────────────────────────────────
 * Two effects, no flash. Total ~300 ms:
 *
 *   1. `.gate-leave` on the form + wordmark + labyrinth:
 *        a 260 ms opacity + small translateY fade. The whole idle
 *        composition drifts down a hair and dims to zero. Ease-out so
 *        the motion settles rather than ending abruptly.
 *
 *   2. `.gate-hairline` (a thin amber line centred in the viewport via
 *      a flex wrapper in Gate.tsx):
 *        materialises at zero width, expands horizontally from the
 *        centre to full viewport width over ~180 ms, holds a beat,
 *        fades out. The sweep itself is the transition's only active
 *        visual element — no colour flashes, no screen fill.
 *
 * Both start together when `phase` flips to `entering`, run in parallel
 * for ~300 ms, and leave the viewport empty at the moment the router
 * navigates. The dashboard side (`.codex-arrival` +
 * `.codex-arrival-hairline`) mirrors the effect in reverse: the
 * hairline contracts back to centre while content fades up.
 *
 * Prior revision removed: a three-layer ignition with radial amber
 * shockwave (`.gate-flash`), rotating conic sunburst (`.gate-rays`),
 * and 9× scale / 1800° rotation on the hero (`.gate-open`). The
 * amber flash was visually loud and the most-complained-about detail.
 */

@keyframes gate-spin-slow {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

@keyframes gate-breath {
  0%, 100% { filter: drop-shadow(0 0 10px var(--amber-glow)); }
  50% { filter: drop-shadow(0 0 20px var(--amber-glow)) drop-shadow(0 0 4px var(--amber)); }
}

/* Shared exit for form + wordmark + labyrinth. Tiny down-drift so the
   whole composition settles away together rather than each piece
   falling independently. */
.gate-leave {
  animation: gate-leave 0.26s cubic-bezier(0.33, 0, 0.67, 1) forwards;
}

@keyframes gate-leave {
  0%   { opacity: 1; transform: translateY(0); }
  100% { opacity: 0; transform: translateY(10px); }
}

/* Horizon hairline. Painted directly (no gradient) with an amber glow
   from box-shadow. The wrapper in Gate.tsx is
   `display: grid; place-items: center`, so as `width` expands from
   zero the bar grows symmetrically outward from the viewport centre.
   On fast machines this runs entirely on the compositor thread. */
.gate-hairline {
  width: 0;
  height: 1px;
  background: var(--amber);
  box-shadow:
    0 0 6px var(--amber),
    0 0 18px var(--amber-glow);
  animation: gate-hairline 0.3s cubic-bezier(0.22, 0.61, 0.36, 1) forwards;
}

@keyframes gate-hairline {
  0%   { width: 0;     opacity: 0; }
  15%  { width: 0;     opacity: 1; }
  55%  { width: 100vw; opacity: 1; }
  100% { width: 100vw; opacity: 0; }
}

/* ── Arrival animation (dashboard side of the entrance) ─────────────────
 * The EntranceWelcome client component picks up the `codex:just-entered`
 * sessionStorage flag set by the Gate and, if present, mounts
 * `.codex-arrival` on the page wrapper for ~280 ms plus a mirrored
 * `.codex-arrival-hairline` that contracts back to the centre.
 *
 * Content fades up from a small downward offset — a quiet reveal,
 * no blur, no scale, no brightness pump. The whole page is visible
 * and fully interactive within 300 ms of navigation. */
.codex-arrival {
  animation: codex-arrival-fade 0.28s cubic-bezier(0.22, 0.61, 0.36, 1) forwards;
}

@keyframes codex-arrival-fade {
  0%   { opacity: 0; transform: translateY(8px); }
  100% { opacity: 1; transform: translateY(0); }
}

/* Mirrored hairline that the dashboard paints on arrival — starts
   at full viewport width and contracts back to a zero-width pinpoint
   at the centre, then fades. Same visual vocabulary as the exit,
   reversed. */
.codex-arrival-hairline {
  width: 100vw;
  height: 1px;
  background: var(--amber);
  box-shadow:
    0 0 6px var(--amber),
    0 0 18px var(--amber-glow);
  animation: codex-arrival-hairline 0.32s cubic-bezier(0.33, 0, 0.67, 1) forwards;
}

@keyframes codex-arrival-hairline {
  0%   { width: 100vw; opacity: 1; }
  55%  { width: 40vw;  opacity: 0.8; }
  100% { width: 0;     opacity: 0; }
}

@media (prefers-reduced-motion: reduce) {
  .gate-leave,
  .gate-hairline,
  .codex-arrival,
  .codex-arrival-hairline { animation: none !important; }
}

/* Currents — uses the public site palette; components keep their legacy
   variable names so this is a theme rebind, not a component rename. */
:root {
  --currents-bg:                 var(--ink);
  --currents-bg-elevated:        var(--stone);
  --currents-border:             var(--border);
  --currents-parchment:          var(--parchment);
  --currents-parchment-dim:      var(--parchment-dim);
  --currents-muted:              var(--parchment-dim);
  --currents-gold:               var(--gold);
  --currents-amber:              var(--amber);
  --currents-stance-agrees:      #8db567;
  --currents-stance-disagrees:   #b95c5c;
  --currents-stance-complicates: var(--amber);
  --currents-stance-abstained:   var(--parchment-dim);

  /* Forecasts — same public site palette as Currents; components keep
     forecast-prefixed variables for domain-specific styling hooks. */
  --forecasts-bg:                var(--ink);
  --forecasts-bg-elevated:       var(--stone);
  --forecasts-border:            var(--border);
  --forecasts-parchment:         var(--parchment);
  --forecasts-parchment-dim:     var(--parchment-dim);
  --forecasts-muted:             var(--parchment-dim);
  --forecasts-cool-gold:         var(--gold);
  --forecasts-prob-yes:          #6fa15c;
  --forecasts-prob-no:           #b95c5c;
  --forecasts-prob-track:        var(--border);

  /* Calibration heatmap (5-step ramp) */
  --forecasts-calib-1:           #5a3a3a;
  --forecasts-calib-2:           #8d5d4d;
  --forecasts-calib-3:           #c9944a;
  --forecasts-calib-4:           #a3a45c;
  --forecasts-calib-5:           #6fa15c;
}

[data-theme="light"] {
  --currents-bg:                 var(--ink);
  --currents-bg-elevated:        var(--stone);
  --currents-border:             var(--border);
  --currents-parchment:          var(--parchment);
  --currents-parchment-dim:      var(--parchment-dim);
  --currents-muted:              var(--parchment-dim);
  --currents-gold:               var(--gold);
  --currents-amber:              var(--amber);
  --currents-stance-agrees:      #3f6f2a;
  --currents-stance-disagrees:   #8b3a2a;
  --currents-stance-complicates: var(--amber);
  --currents-stance-abstained:   var(--parchment-dim);

  --forecasts-bg:                var(--ink);
  --forecasts-bg-elevated:       var(--stone);
  --forecasts-border:            var(--border);
  --forecasts-parchment:         var(--parchment);
  --forecasts-parchment-dim:     var(--parchment-dim);
  --forecasts-muted:             var(--parchment-dim);
  --forecasts-cool-gold:         var(--gold);
  --forecasts-prob-yes:          var(--success);
  --forecasts-prob-no:           var(--ember);
  --forecasts-prob-track:        var(--border);
  --forecasts-calib-1:           #d8b6b0;
  --forecasts-calib-2:           #c69274;
  --forecasts-calib-3:           #ad7a34;
  --forecasts-calib-4:           #74803d;
  --forecasts-calib-5:           #4f7a35;
}

[data-theseus-x-embed] {
  background: var(--currents-bg-elevated);
}

[data-theseus-x-embed="page"] {
  background: var(--currents-bg);
}

[data-theseus-x-embed] > blockquote.twitter-tweet {
  background: inherit;
  border-radius: 16px;
  overflow: hidden;
}

[data-theseus-x-embed]:has(> iframe) {
  background: var(--currents-bg-elevated);
}

[data-theseus-x-embed="page"]:has(> iframe) {
  background: var(--currents-bg);
}

@keyframes currents-pulse {
  0%, 100% { opacity: 1.0; transform: scale(1.0); }
  50%      { opacity: 0.55; transform: scale(0.85); }
}

@keyframes currents-fade-in {
  from { opacity: 0; transform: translateY(-4px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes forecasts-prob-shimmer {
  0%, 100% { opacity: 0.85; }
  50%      { opacity: 1.0; }
}

.currents-fade-in { animation: currents-fade-in 0.4s ease-out; }

.currents-pulse {
  display: inline-block;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--currents-gold);
  box-shadow: 0 0 8px rgba(212, 160, 23, 0.55);
  animation: currents-pulse 1.8s ease-in-out infinite;
}

.forecasts-prob-bar {
  height: 6px;
  border-radius: 3px;
  background: var(--forecasts-prob-track);
  overflow: hidden;
}

.forecasts-prob-bar > .fill {
  height: 100%;
  background: var(--forecasts-prob-yes);
  transition: width 600ms ease-out;
}

/* Transcript explorer */
.transcript-shell {
  display: grid;
  gap: 1rem;
  margin: 0 auto;
  max-width: 1220px;
  padding: 1.5rem 1rem 4rem;
}

.transcript-header {
  align-items: flex-start;
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  justify-content: space-between;
}

.transcript-header h1 {
  color: var(--amber);
  font-family: "Cinzel Decorative", "Cinzel", serif;
  line-height: 1.08;
  margin: 0.25rem 0 0;
}

.transcript-backlink {
  color: var(--amber-dim);
  font-size: 0.65rem;
  text-decoration: none;
}

.transcript-meta {
  color: var(--parchment-dim);
  font-size: 0.65rem;
  margin: 0.45rem 0 0;
}

.transcript-toolbar {
  align-items: flex-end;
  display: grid;
  gap: 0.6rem;
  justify-items: end;
}

.transcript-public-toggle {
  align-items: center;
  color: var(--parchment-dim);
  display: flex;
  flex-wrap: wrap;
  gap: 0.45rem;
  justify-content: flex-end;
}

.transcript-public-toggle > .mono {
  border: 1px solid rgba(232, 225, 211, 0.14);
  color: var(--parchment-dim);
  font-size: 0.58rem;
  letter-spacing: 0.18em;
  padding: 0.24rem 0.45rem;
  text-transform: uppercase;
}

.transcript-blurb-card {
  display: grid;
  gap: 0.75rem;
  padding: 1rem;
}

.transcript-blurb-card h2,
.transcript-related-panel h2 {
  color: var(--amber-dim);
  font-size: 0.64rem;
  letter-spacing: 0.2em;
  margin: 0;
  text-transform: uppercase;
}

.transcript-blurb-card p {
  color: var(--parchment);
  font-family: "EB Garamond", Georgia, serif;
  font-size: 1.14rem;
  font-style: italic;
  line-height: 1.55;
  margin: 0;
  max-width: 76ch;
}

.transcript-chip-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.45rem;
}

.transcript-chip {
  border: 1px solid rgba(205, 151, 67, 0.35);
  color: var(--amber);
  font-size: 0.78rem;
  line-height: 1.2;
  padding: 0.38rem 0.55rem;
  text-decoration: none;
}

.transcript-insight-grid {
  align-items: start;
  display: grid;
  gap: 1rem;
  grid-template-columns: minmax(0, 1fr) minmax(280px, 0.34fr);
}

.conversation-geometry {
  display: grid;
  gap: 1rem;
  overflow: hidden;
}

.conversation-geometry-header {
  align-items: flex-start;
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  justify-content: space-between;
}

.conversation-geometry-kicker,
.conversation-catalyst-kind {
  color: var(--amber-dim);
  font-size: 0.62rem;
  letter-spacing: 0.18em;
  margin: 0;
  text-transform: uppercase;
}

.conversation-geometry h2 {
  color: var(--amber);
  font-family: "Cinzel", serif;
  font-size: 1.08rem;
  letter-spacing: 0.12em;
  margin: 0.15rem 0 0;
  text-transform: uppercase;
}

.conversation-geometry-header p:not(.conversation-geometry-kicker),
.conversation-geometry-note {
  color: var(--parchment-dim);
  font-size: 0.86rem;
  line-height: 1.45;
  margin: 0.35rem 0 0;
}

.conversation-geometry-tabs {
  align-items: center;
  border: 1px solid rgba(232, 225, 211, 0.12);
  display: flex;
  flex-wrap: wrap;
  gap: 0.25rem;
  padding: 0.25rem;
}

.conversation-tab {
  align-items: center;
  background: transparent;
  border: 1px solid transparent;
  color: var(--parchment-dim);
  cursor: pointer;
  display: inline-flex;
  font-family: "IBM Plex Mono", monospace;
  font-size: 0.65rem;
  gap: 0.35rem;
  letter-spacing: 0.12em;
  min-height: 2rem;
  padding: 0.42rem 0.58rem;
  text-transform: uppercase;
}

.conversation-tab[aria-pressed="true"] {
  background: rgba(205, 151, 67, 0.12);
  border-color: rgba(205, 151, 67, 0.45);
  color: var(--amber);
}

.conversation-map-grid {
  align-items: stretch;
  display: grid;
  gap: 1rem;
  grid-template-columns: minmax(0, 1fr) minmax(230px, 0.34fr);
}

.conversation-map-frame {
  border: 1px solid rgba(232, 225, 211, 0.12);
  min-height: 22rem;
  overflow: hidden;
}

.conversation-map {
  aspect-ratio: 16 / 9;
  display: block;
  height: 100%;
  min-height: 22rem;
  width: 100%;
}

.conversation-edge {
  stroke: rgba(58, 122, 168, 0.62);
  stroke-linecap: round;
}

.conversation-node {
  fill: rgba(233, 163, 56, 0.92);
  stroke: rgba(239, 226, 199, 0.72);
  stroke-width: 0.8;
}

.conversation-node-label {
  fill: var(--parchment);
  font-family: "IBM Plex Mono", monospace;
  font-size: 3px;
  letter-spacing: 0.02em;
  text-anchor: middle;
}

.conversation-year-card {
  border: 1px solid rgba(232, 225, 211, 0.12);
  display: grid;
  gap: 0.75rem;
  padding: 0.9rem;
}

.conversation-year-card > svg {
  color: var(--amber);
}

.conversation-year-card > .mono {
  color: var(--amber);
  font-size: 0.64rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.conversation-year-card p {
  color: var(--parchment-dim);
  font-size: 0.86rem;
  line-height: 1.5;
  margin: 0;
}

.conversation-year-card dl {
  display: grid;
  gap: 0.7rem;
  margin: 0;
}

.conversation-year-card dt {
  color: var(--parchment-dim);
  font-family: "IBM Plex Mono", monospace;
  font-size: 0.58rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.conversation-year-card dd {
  color: var(--parchment);
  margin: 0.12rem 0 0;
}

.conversation-year-card dd span {
  color: var(--amber-dim);
}

.conversation-weighting {
  border-top: 1px solid rgba(232, 225, 211, 0.12);
  display: grid;
}

.conversation-speaker-row {
  align-items: center;
  border-bottom: 1px solid rgba(232, 225, 211, 0.1);
  display: grid;
  gap: 0.8rem;
  grid-template-columns: minmax(160px, 0.45fr) minmax(170px, 0.28fr) minmax(0, 0.27fr);
  padding: 0.8rem 0;
}

.conversation-speaker-name {
  color: var(--amber);
  display: block;
  font-family: "Cinzel", serif;
  font-size: 0.95rem;
  letter-spacing: 0.08em;
  text-decoration: none;
}

.conversation-speaker-row .mono {
  color: var(--parchment-dim);
  display: block;
  font-size: 0.6rem;
  letter-spacing: 0.1em;
  margin-top: 0.2rem;
  text-transform: uppercase;
}

.conversation-share {
  display: grid;
  gap: 0.35rem;
}

.conversation-share-bar {
  background: rgba(232, 225, 211, 0.08);
  height: 0.46rem;
  overflow: hidden;
}

.conversation-share-bar span {
  background: linear-gradient(90deg, var(--amber), var(--info));
  display: block;
  height: 100%;
}

.conversation-term-row {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem;
}

.conversation-term {
  border: 1px solid rgba(58, 122, 168, 0.36);
  color: #8eb6d4;
  font-family: "IBM Plex Mono", monospace;
  font-size: 0.58rem;
  letter-spacing: 0.08em;
  padding: 0.18rem 0.34rem;
}

.conversation-catalyst-list {
  display: grid;
  gap: 0.8rem;
  list-style: none;
  margin: 0;
  padding: 0;
}

.conversation-catalyst {
  border-bottom: 1px solid rgba(232, 225, 211, 0.1);
  display: grid;
  gap: 0.45rem;
  padding: 0 0 0.8rem;
}

.conversation-catalyst > div:first-child {
  align-items: baseline;
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.conversation-catalyst a {
  color: var(--amber);
  font-family: "Cinzel", serif;
  font-size: 0.9rem;
  letter-spacing: 0.08em;
  text-decoration: none;
}

.conversation-catalyst p {
  color: var(--parchment);
  font-size: 0.95rem;
  line-height: 1.45;
  margin: 0;
}

.conversation-catalyst strong {
  color: var(--parchment-dim);
  font-weight: 500;
}

.transcript-methodology-panel {
  align-self: start;
  display: grid;
  gap: 0.9rem;
  padding: 0.9rem;
}

.transcript-methodology-head {
  align-items: flex-start;
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  justify-content: space-between;
}

.transcript-methodology-head h2 {
  color: var(--amber-dim);
  font-size: 0.64rem;
  letter-spacing: 0.2em;
  margin: 0;
  text-transform: uppercase;
}

.transcript-methodology-head p {
  color: var(--parchment-dim);
  font-size: 0.86rem;
  line-height: 1.45;
  margin: 0.35rem 0 0;
}

.transcript-methodology-head > .mono {
  color: var(--amber);
  font-size: 0.62rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
}

.transcript-methodology-list {
  display: grid;
  gap: 0.75rem;
  list-style: none;
  margin: 0;
  padding: 0;
}

.transcript-methodology-card {
  border: 1px solid rgba(232, 225, 211, 0.12);
  display: grid;
  gap: 0.45rem;
  padding: 0.85rem;
}

.transcript-methodology-card-head {
  align-items: center;
  display: flex;
  gap: 0.5rem;
  justify-content: space-between;
}

.transcript-methodology-card-head .mono {
  color: #8eb6d4;
  font-size: 0.58rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.transcript-methodology-card h3 {
  color: var(--amber);
  font-family: "Cinzel", serif;
  font-size: 0.94rem;
  letter-spacing: 0.06em;
  margin: 0;
}

.transcript-methodology-summary {
  color: var(--parchment);
  font-size: 0.84rem;
  line-height: 1.45;
  margin: 0;
}

.transcript-methodology-details {
  border-top: 1px solid rgba(232, 225, 211, 0.1);
  display: grid;
  gap: 0.45rem;
  margin: 0;
  padding-top: 0.55rem;
}

.transcript-methodology-detail {
  display: grid;
  gap: 0.18rem;
}

.transcript-methodology-detail dt {
  color: var(--amber-dim);
  font-size: 0.56rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.transcript-methodology-detail dd {
  color: var(--parchment-dim);
  font-size: 0.8rem;
  line-height: 1.45;
  margin: 0;
}

.transcript-methodology-empty {
  border: 1px solid rgba(232, 225, 211, 0.12);
  color: var(--parchment-dim);
  display: grid;
  font-size: 0.84rem;
  gap: 0.35rem;
  line-height: 1.45;
  padding: 0.85rem;
}

.transcript-methodology-empty strong {
  color: var(--parchment);
}

.transcript-methodology-empty p {
  margin: 0;
}

.transcript-source-structure {
  align-self: start;
  display: grid;
  gap: 0.9rem;
  padding: 0.9rem;
}

.transcript-source-structure-list {
  display: grid;
  gap: 0.45rem;
  list-style: none;
  margin: 0;
  padding: 0;
}

.transcript-source-structure-list a {
  border: 1px solid rgba(232, 225, 211, 0.12);
  color: var(--parchment);
  display: grid;
  gap: 0.25rem;
  padding: 0.65rem;
  text-decoration: none;
}

.transcript-source-structure-list .mono {
  color: var(--amber-dim);
  font-size: 0.56rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.transcript-source-structure-list strong {
  color: var(--parchment);
  font-size: 0.84rem;
  font-weight: 500;
  line-height: 1.35;
}

.transcript-grid {
  align-items: start;
  display: grid;
  gap: 1rem;
  grid-template-columns: minmax(0, 1fr) 300px;
}

.transcript-main,
.transcript-primary {
  display: grid;
  gap: 0.55rem;
  min-width: 0;
}

.transcript-side-rail {
  display: grid;
  gap: 0.85rem;
  position: sticky;
  top: 5.25rem;
}

.transcript-reader-toolbar {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  justify-content: space-between;
  margin-bottom: 0.35rem;
}

.transcript-reader-search {
  display: grid;
  flex: 1 1 240px;
  gap: 0.25rem;
}

.transcript-reader-search > .mono {
  color: var(--amber-dim);
  font-size: 0.6rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.transcript-reader-search input {
  background: rgba(14, 10, 6, 0.4);
  border: 1px solid rgba(232, 225, 211, 0.18);
  color: var(--parchment);
  font: inherit;
  padding: 0.45rem 0.6rem;
}

.transcript-reader-search input:focus {
  border-color: rgba(205, 151, 67, 0.6);
  outline: none;
}

.transcript-reader-count {
  color: var(--parchment-dim);
  font-size: 0.62rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.transcript-reader-empty {
  color: var(--parchment-dim);
  font-size: 0.95rem;
  padding: 0.85rem 0;
}

.transcript-search-hit {
  background: rgba(205, 151, 67, 0.28);
  color: inherit;
  padding: 0 0.1em;
}

.transcript-chunk-copy {
  background: transparent;
  border: 1px solid rgba(232, 225, 211, 0.16);
  color: var(--parchment-dim);
  cursor: pointer;
  display: inline-block;
  font-family: "IBM Plex Mono", monospace;
  font-size: 0.56rem;
  letter-spacing: 0.14em;
  margin-top: 0.25rem;
  padding: 0.18rem 0.4rem;
  text-transform: uppercase;
}

.transcript-chunk-copy:hover {
  border-color: rgba(205, 151, 67, 0.45);
  color: var(--amber);
}

.transcript-chunk-index {
  color: var(--parchment-dim);
  font-size: 0.62rem;
}

.transcript-body {
  max-width: 70ch;
}

.transcript-status-row {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin: 0.45rem 0 0;
}

.transcript-status-note {
  color: var(--parchment-dim);
  font-size: 0.62rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.transcript-section-nav {
  display: grid;
  gap: 0.55rem;
  padding: 0.85rem;
}

.transcript-section-nav h2 {
  color: var(--amber-dim);
  font-size: 0.62rem;
  letter-spacing: 0.18em;
  margin: 0;
  text-transform: uppercase;
}

.transcript-section-nav ul {
  display: grid;
  gap: 0.3rem;
  list-style: none;
  margin: 0;
  padding: 0;
}

.transcript-section-nav a {
  color: var(--parchment);
  display: block;
  font-size: 0.86rem;
  line-height: 1.35;
  text-decoration: none;
}

.transcript-section-nav a:hover {
  color: var(--amber);
}

.transcript-analysis {
  display: grid;
  gap: 0.85rem;
  margin-top: 0.5rem;
  padding-top: 1rem;
  border-top: 1px solid rgba(232, 225, 211, 0.12);
}

.transcript-analysis-kicker {
  color: var(--amber-dim);
  font-size: 0.62rem;
  letter-spacing: 0.2em;
  margin: 0;
  text-transform: uppercase;
}

.transcript-analysis-note {
  color: var(--parchment-dim);
  font-size: 0.86rem;
  line-height: 1.5;
  margin: 0;
}

.transcript-index-list {
  display: grid;
  gap: 0.7rem;
  list-style: none;
  margin: 0;
  padding: 0;
}

.transcript-index-row {
  display: grid;
  gap: 0.55rem;
  padding: 0.85rem 1rem;
}

.transcript-index-row-head {
  align-items: baseline;
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
}

.transcript-index-kind {
  border: 1px solid rgba(232, 225, 211, 0.16);
  color: var(--parchment-dim);
  font-size: 0.58rem;
  letter-spacing: 0.18em;
  padding: 0.18rem 0.42rem;
}

.transcript-index-kind-audio {
  border-color: rgba(205, 151, 67, 0.55);
  color: var(--amber);
}

.transcript-index-kind-transcript {
  border-color: rgba(58, 122, 168, 0.55);
  color: var(--info);
}

.transcript-index-title {
  font-family: "EB Garamond", serif;
  font-size: 1.08rem;
  margin: 0;
}

.transcript-index-title a {
  color: var(--parchment);
  text-decoration: none;
}

.transcript-index-title a:hover {
  color: var(--amber);
}

.transcript-index-fields {
  display: grid;
  gap: 0.45rem 1rem;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
  margin: 0;
}

.transcript-index-fields > div {
  display: grid;
  gap: 0.1rem;
}

.transcript-index-fields dt {
  color: var(--amber-dim);
  font-size: 0.54rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.transcript-index-fields dd {
  color: var(--parchment);
  font-size: 0.82rem;
  margin: 0;
}

.transcript-index-blurb {
  color: var(--parchment-dim);
  font-size: 0.84rem;
  line-height: 1.45;
  margin: 0;
  max-width: 70ch;
}

.transcript-chunk {
  border: 1px solid transparent;
  border-radius: 6px;
  padding: 0.35rem 0.45rem;
  scroll-margin-top: 6rem;
  transition: background 180ms ease, border-color 180ms ease, box-shadow 180ms ease;
}

.transcript-chunk.chunk-highlight {
  background: rgba(205, 151, 67, 0.14);
  border-color: rgba(205, 151, 67, 0.55);
  box-shadow: 0 0 0 1px rgba(205, 151, 67, 0.16);
}

.transcript-chunk-grid {
  display: grid;
  gap: 0.75rem;
  grid-template-columns: 4.9rem minmax(0, 1fr);
}

.transcript-time-slot {
  padding-top: 0.25rem;
}

.transcript-time {
  color: var(--amber-dim);
  font-size: 0.63rem;
  text-decoration: none;
}

.transcript-body {
  color: var(--parchment);
  font-family: "EB Garamond", Georgia, serif;
  font-size: 1.06rem;
  line-height: 1.62;
  margin: 0;
}

.transcript-speaker {
  color: var(--amber);
  font-family: var(--font-sans, inherit);
  font-size: 0.9rem;
  letter-spacing: 0.02em;
}

.transcript-related-rail {
  padding: 0.85rem;
  position: sticky;
  top: 5.25rem;
}

.transcript-related-drawer {
  display: none;
  padding: 0.85rem;
}

.transcript-related-drawer > summary {
  color: var(--amber);
  cursor: pointer;
  font-size: 0.65rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.transcript-related-panel {
  display: grid;
  gap: 0.7rem;
}

.transcript-related-list {
  display: grid;
  gap: 0.55rem;
}

.transcript-related-card {
  border: 1px solid rgba(232, 225, 211, 0.12);
  color: inherit;
  display: grid;
  gap: 0.35rem;
  padding: 0.7rem;
  text-decoration: none;
}

.transcript-related-card span {
  color: var(--amber-dim);
  font-size: 0.56rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.transcript-related-card strong {
  color: var(--parchment);
  font-size: 0.88rem;
  line-height: 1.35;
}

.transcript-related-card em,
.transcript-related-empty {
  color: var(--parchment-dim);
  font-size: 0.78rem;
  line-height: 1.45;
}

.transcript-empty {
  color: var(--parchment-dim);
  padding: 1rem;
}

@media (max-width: 860px) {
  .transcript-insight-grid,
  .conversation-map-grid,
  .conversation-speaker-row {
    grid-template-columns: 1fr;
  }

  .conversation-map-frame,
  .conversation-map {
    min-height: 18rem;
  }

  .transcript-grid {
    grid-template-columns: 1fr;
  }

  .transcript-related-rail {
    display: none;
  }

  .transcript-related-drawer {
    display: block;
  }

  .transcript-chunk-grid {
    grid-template-columns: 1fr;
    gap: 0.2rem;
  }

  .transcript-time-slot {
    min-height: 0;
    padding-top: 0;
  }
}

/* ═════════════════════════════════════════════════════════════════════════
 * Public site — responsive header + mobile reading layout.
 *
 * Breakpoint: 720px. Above it, PublicHeader renders inline links and the
 * founder-portal CTA; below it the same component hides those and exposes
 * <MobileNavDrawer />. The article body bumps to 17–18px with looser
 * paragraph spacing so reading at 360–414px feels comfortable rather than
 * cramped. Hyphenation rules from the existing `.public-article-body`
 * carry through; the rules below only widen `max-width` constraints and
 * strengthen overflow protection for quotes / footnotes / pre blocks.
 *
 * Hero ASCII / heavy SVG: components live outside this stylesheet, but
 * the breakpoint they should respect when shrinking-or-replacing on
 * mobile is the same 720px boundary used here.
 * ═════════════════════════════════════════════════════════════════════════ */

.public-header {
  align-items: center;
  backdrop-filter: blur(6px);
  background: linear-gradient(
    180deg,
    rgba(14, 10, 6, 0.94) 0%,
    rgba(14, 10, 6, 0.82) 100%
  );
  border-bottom: 1px solid rgba(212, 160, 23, 0.18);
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  justify-content: space-between;
  padding: 0.85rem 1.5rem;
  position: sticky;
  top: 0;
  -webkit-backdrop-filter: blur(6px);
  z-index: 5;
}

[data-theme="light"] .public-header {
  background: linear-gradient(
    180deg,
    rgba(242, 232, 217, 0.94) 0%,
    rgba(242, 232, 217, 0.82) 100%
  );
}

.public-header-brand {
  align-items: center;
  display: flex;
  gap: 0.55rem;
  text-decoration: none;
}

.public-header-nav {
  align-items: center;
  display: flex;
  font-size: 0.58rem;
  gap: 0.9rem;
  letter-spacing: 0.22em;
  margin-left: auto;
  margin-right: 1rem;
  text-transform: uppercase;
}

.public-header-actions {
  align-items: center;
  display: flex;
  gap: 0.6rem;
}

.public-header-cta {
  border: 1px solid var(--amber-dim);
  border-radius: 3px;
  color: var(--amber);
  font-size: 0.6rem;
  letter-spacing: 0.26em;
  padding: 0.4rem 0.9rem;
  text-decoration: none;
  text-transform: uppercase;
  transition: all 0.18s ease;
}

.public-header-mobile {
  display: none;
}

@media (max-width: 720px) {
  .public-header {
    padding: 0.7rem 1rem;
  }

  .public-header-tagline {
    display: none;
  }

  .public-header-nav,
  .public-header-actions {
    display: none;
  }

  .public-header-mobile {
    display: flex;
    margin-left: auto;
  }
}

/* Hamburger trigger — three amber bars, 44×44 hit target. */
.public-nav-trigger {
  align-items: center;
  background: transparent;
  border: 1px solid var(--amber-dim);
  border-radius: 3px;
  color: var(--amber);
  cursor: pointer;
  display: inline-flex;
  height: 44px;
  justify-content: center;
  padding: 0;
  width: 44px;
}

.public-nav-trigger:focus-visible {
  outline: 2px solid var(--amber);
  outline-offset: 2px;
}

.public-nav-trigger-bars {
  display: inline-flex;
  flex-direction: column;
  gap: 4px;
  height: 14px;
  justify-content: space-between;
  width: 18px;
}

.public-nav-trigger-bars > span {
  background: var(--amber);
  display: block;
  height: 2px;
  width: 100%;
}

.public-nav-scrim {
  align-items: stretch;
  background: rgba(8, 7, 10, 0.55);
  display: flex;
  inset: 0;
  justify-content: flex-end;
  position: fixed;
  z-index: 10010;
}

.public-nav-drawer {
  background: var(--stone);
  border-left: 1px solid var(--border);
  box-shadow: -10px 0 30px rgba(0, 0, 0, 0.45);
  color: var(--parchment);
  display: flex;
  flex-direction: column;
  max-width: 320px;
  outline: none;
  padding: 1.1rem 1.25rem 1.5rem;
  width: min(82vw, 320px);
}

.public-nav-drawer-head {
  align-items: center;
  display: flex;
  justify-content: space-between;
  margin-bottom: 1rem;
}

.public-nav-drawer-title {
  color: var(--amber);
  font-size: 0.7rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
}

.public-nav-drawer-close {
  background: transparent;
  border: 1px solid var(--border);
  border-radius: 3px;
  color: var(--parchment-dim);
  cursor: pointer;
  font-size: 1.4rem;
  height: 40px;
  line-height: 1;
  width: 40px;
}

.public-nav-drawer-close:focus-visible {
  outline: 2px solid var(--amber);
  outline-offset: 2px;
}

.public-nav-drawer-list {
  display: flex;
  flex-direction: column;
  gap: 0.2rem;
}

.public-nav-drawer-link {
  border-bottom: 1px solid rgba(212, 160, 23, 0.12);
  color: var(--amber);
  display: block;
  font-size: 0.78rem;
  letter-spacing: 0.22em;
  padding: 1rem 0;
  text-decoration: none;
  text-transform: uppercase;
}

.public-nav-drawer-link:focus-visible {
  outline: 2px solid var(--amber);
  outline-offset: 2px;
}

.public-nav-drawer-foot {
  align-items: center;
  display: flex;
  gap: 0.75rem;
  justify-content: space-between;
  margin-top: auto;
  padding-top: 1.25rem;
}

.public-nav-drawer-cta {
  border: 1px solid var(--amber-dim);
  border-radius: 3px;
  color: var(--amber);
  font-size: 0.7rem;
  letter-spacing: 0.22em;
  padding: 0.6rem 0.9rem;
  text-decoration: none;
  text-transform: uppercase;
}

.public-nav-drawer-cta:focus-visible {
  outline: 2px solid var(--amber);
  outline-offset: 2px;
}

/* ── Mobile reading layout ──────────────────────────────────────────────── */

@media (max-width: 720px) {
  body {
    /* 17px stays the legible default for body copy on phones; the
       article container below bumps to 18px for prose. */
    font-size: 17px;
  }

  .public-container {
    padding: 1.5rem 1.05rem 3rem;
  }

  .public-article-body {
    font-size: 1.06rem; /* ≈18px against the 17px root */
    line-height: 1.72;
    /* 60–66ch line length. The prose body keeps `max-width: 70ch` on
       desktop; on mobile the viewport itself caps the measure, so we
       just relax the cap and let padding control the gutter. */
    max-width: 64ch;
  }

  .public-article-body p {
    margin: 0 0 1.2rem;
  }

  .public-article-body blockquote {
    border-left: 2px solid var(--amber-dim);
    color: var(--parchment-dim);
    margin: 1.1rem 0;
    overflow-wrap: anywhere;
    padding: 0.2rem 0.85rem;
  }

  .public-article-body pre,
  .public-article-body code {
    overflow-x: auto;
    word-break: break-word;
    /* Allow code that *can* wrap to do so; pre keeps its own scroll. */
    white-space: pre-wrap;
  }

  .public-article-body pre {
    white-space: pre;
  }

  .public-article-body sup,
  .public-article-body .footnote,
  .public-article-body a {
    overflow-wrap: anywhere;
    word-break: break-word;
  }

  /* Article post page wraps text in `.post-body` — bump it the same way. */
  .post-body {
    font-size: 1.06rem !important;
    line-height: 1.72 !important;
  }

  .post-body p {
    margin: 0 0 1.2rem !important;
  }

  /* Provenance gutter: collapse beside a 360px article body.
     ProvenanceArticle uses `display: grid; grid-template-columns: auto 1fr`,
     stacking the gutter above the prose works better than letting it
     squeeze the measure. */
  [data-testid="provenance-article"] > div:last-child {
    grid-template-columns: 1fr !important;
  }
}

/* Sticky bottom toolbar — used on mobile to keep the provenance toggle
   reachable while the visitor reads. Hidden above 720px (the toggle is
   already inline). */
.public-mobile-toolbar {
  display: none;
}

@media (max-width: 720px) {
  .public-mobile-toolbar {
    align-items: center;
    background: rgba(14, 10, 6, 0.94);
    -webkit-backdrop-filter: blur(8px);
    backdrop-filter: blur(8px);
    border-top: 1px solid rgba(212, 160, 23, 0.18);
    bottom: 0;
    display: flex;
    gap: 0.5rem;
    justify-content: center;
    left: 0;
    padding: 0.55rem 0.85rem calc(0.55rem + env(safe-area-inset-bottom, 0px));
    position: fixed;
    right: 0;
    z-index: 20;
  }

  [data-theme="light"] .public-mobile-toolbar {
    background: rgba(242, 232, 217, 0.96);
  }

  /* Reserve room so the fixed toolbar never covers a footer link. */
  .public-container,
  article {
    padding-bottom: 5rem;
  }
}

