const sp = await searchParams;
const chunkCount = upload.chunks.length;
const analyzedText =
  upload.chunks.map((chunk) => chunk.text).join("\n\n").trim() ||
  upload.textContent?.trim() ||
  "";
const rawText = upload.textContent?.trim() || "";
const rawDiffers = Boolean(rawText && analyzedText && rawText !== analyzedText);
const hasTranscriptSurface = chunkCount > 0 || Boolean(rawText);
const transcriptionSucceeded = hasTranscriptSurface;
const analysisFailed = upload.status === "failed" && transcriptionSucceeded;
const fullyFailed = upload.status === "failed" && !transcriptionSucceeded;
const canPublish = canWrite(founder.role) && Boolean(analyzedText);

return (
  <main style={{ display: "grid", gap: "1rem", margin: "0 auto", maxWidth: 1040, padding: "1.5rem 1rem 3rem" }}>
    <header style={{ display: "flex", flexWrap: "wrap", gap: "0.75rem", justifyContent: "space-between" }}>
      <div>
        <Link className="mono" href="/knowledge?tab=library" style={{ color: "var(--amber-dim)", fontSize: "0.65rem", textDecoration: "none" }}>
          Library
        </Link>
        <h1 style={{ color: "var(--amber)", fontFamily: "'Cinzel Decorative', 'Cinzel', serif", margin: "0.25rem 0 0" }}>
          {upload.title}
        </h1>
        <p className="mono" style={{ color: "var(--parchment-dim)", fontSize: "0.65rem", margin: "0.35rem 0 0" }}>
          {upload.sourceType} / {founderDisplayName(upload.founder)} / {new Date(upload.createdAt).toLocaleDateString()}
        </p>
        <p
          className="mono"
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: "0.4rem",
            alignItems: "center",
            margin: "0.5rem 0 0",
          }}
        >
          <span
            className={`badge ${analysisFailed ? "badge-ingested" : `badge-${upload.status}`}`}
          >
            {analysisFailed ? "transcript ready" : upload.status}
          </span>
          {analysisFailed ? (
            <span className="badge badge-failed">analysis failed</span>
          ) : null}
          {hasTranscriptSurface ? (
            <span style={{ color: "var(--parchment-dim)", fontSize: "0.6rem", letterSpacing: "0.14em" }}>
              {chunkCount > 0 ? `${chunkCount} chunks` : "extracted text only"}
            </span>
          ) : null}
        </p>
      </div>
      <PublishToToolbar
        artifactId={upload.id}
        artifactType="upload"
        disabled={!canPublish}
      />
    </header>

    {sp.error ? (
      <p role="alert" style={{ color: "var(--ember)", margin: 0 }}>
        Publish draft failed: {sp.error}
      </p>
    ) : null}

    {analysisFailed ? (
      <section className="portal-card" style={{ padding: "1rem", display: "grid", gap: "0.45rem" }}>
        <p style={{ color: "var(--ember)", margin: 0, fontSize: "0.95rem" }}>
          Transcription succeeded; downstream Noosphere analysis failed.
        </p>
        <p style={{ color: "var(--parchment-dim)", margin: 0, fontSize: "0.85rem", lineHeight: 1.55 }}>
          The transcript is readable below and on the transcript surface. Re-run analysis to recover methodology profiles and conclusion harvest.
        </p>
      </section>
    ) : null}

    {fullyFailed ? (
      <section className="portal-card" style={{ padding: "1rem" }}>
        <p style={{ color: "var(--ember)", margin: 0, fontSize: "0.95rem" }}>
          Extraction failed; no transcript or text was produced. Re-upload or re-run extraction.
        </p>
      </section>
    ) : null}

    {!analyzedText && !fullyFailed ? (
      <section className="portal-card" style={{ color: "var(--parchment-dim)", padding: "1rem" }}>
        This upload has no extracted text yet, so it cannot be formatted into a Substack draft.
      </section>
    ) : null}

    <section className="portal-card" style={{ display: "grid", gap: "0.65rem", padding: "1rem" }}>
      <div className="mono" style={{ color: "var(--parchment-dim)", fontSize: "0.64rem" }}>
        {upload.originalName} / {upload.mimeType} / {(upload.fileSize / 1024).toFixed(0)} KB / {upload.visibility}
      </div>
      {upload.description ? (
        <p style={{ color: "var(--parchment-dim)", lineHeight: 1.55, margin: 0 }}>
          {upload.description}
        </p>
      ) : null}
      {hasTranscriptSurface ? (
        <Link
          className="mono"
          href={`/transcripts/${upload.id}`}
          style={{
            color: "var(--gold)",
            fontSize: "0.78rem",
            textDecoration: "none",
            letterSpacing: "0.12em",
            textTransform: "uppercase",
          }}
        >
          Open transcript ({chunkCount > 0 ? `${chunkCount} chunks` : "raw text"})
        </Link>
      ) : null}
    </section>

